bool test_transactional_update(const std::string& nodeName) {
    // 1. Create observer nodes
    auto sourceNode = std::make_shared<TestTransactionalObserver>("source");
    auto targetNode = std::make_shared<TestTransactionalObserver>(nodeName);

    // 2. Get observer graph instance
    auto& graph = reaction::ObserverGraph::getInstance();

    // 3. Set up initial relationship: source observes target
    graph.addObserver(sourceNode, targetNode);

    // 4. Notify target and verify relationship works
    targetNode->reset();
    sourceNode->reset();

    // Trigger change on target node
    targetNode->valueChanged(true);

    // Verify source node was notified
    if (!sourceNode->wasChanged()) {
        std::cerr << "Initial relationship verification failed!" << std::endl;
        return false;
    }

    // 5. Reset observer for next test
    sourceNode->reset();
    targetNode->reset();

    bool cycleDetected = false;

    // 6. Attempt transactional update that would create cycle
    // 7. Catch cycle exception if thrown
    try {
        // This should create a cycle: source observes target, and target observes source
        graph.updateObserversTransactional(sourceNode, targetNode);
        graph.updateObserversTransactional(targetNode, sourceNode);
    } catch (const reaction::DependencyCycleException& e) {
        cycleDetected = true;
        std::cout << "Cycle exception caught as expected: " << e.what() << std::endl;
