    auto a = reaction::var(initialA);
    auto b = reaction::var(initialB);

    // 2. Create a reactive variable to track recompute count
    auto recompute_count = reaction::var(0);

    // 3. Create a calculation that sums a and b and increments the recompute count
    auto sum_calc = reaction::calc([&recompute_count](int a_val, int b_val) {
        // Increment recompute count using value() method
        recompute_count.value(recompute_count.get() + 1);
        return a_val + b_val;
    }, a, b);

    // 4. Perform non-batch updates on a and b using value() method
    a.value(nonBatchA);
    b.value(nonBatchB);

    // 5. Get recompute count after non-batch updates using get() method
    int count_after_non_batch = recompute_count.get();

    // 6. Create batch context using reaction::batch
    auto batch_update = reaction::batch([&a, &b, batchA, batchB]() {
        // 7. Execute batch with the batched updates
        a.value(batchA);
        b.value(batchB);
    });

    // Execute the batch
    batch_update.execute();

    // 8. Get recompute count after batch updates
    int count_after_batch = recompute_count.get();

    // 9. Return the tuple with final sum, count after non-batch, and count after batch
    return std::make_tuple(sum_calc.get(), count_after_non_batch, count_after_batch);
}

}  // namespace test_reaction
