    // 3. Register nodes
    graph.addNode(&node1);
    graph.addNode(&node2);
    graph.addNode(&node3);

    // 4. Set up direct observer relationship: node1 observes node2
    node1.addObserver(&node2);

    // 5. Set up transitive observer relationship: node2 observes node3
    node2.addObserver(&node3);

    // 6. Create NodeSet to store collected observers
    std::set<reaction::NodePtr> observers;

    // 7. Populate cache data by calling collectObservers()
    node1.collectObservers(observers);

    // 8. Get cache statistics before cleanup
    auto cacheStatsBefore = graph.getCacheStats();
    size_t graphEntriesBeforeCleanup = cacheStatsBefore.graphTraversalCacheStats.totalEntries;

    // 9. Trigger cache cleanup
