    // 10. Get cache statistics after cleanup
    auto cacheStatsAfter = graph.getCacheStats();
    size_t graphEntriesAfterCleanup = cacheStatsAfter.graphTraversalCacheStats.totalEntries;
    double graphHitRatioAfterCleanup = cacheStatsAfter.graphTraversalCacheStats.hitRatio;

    // 11. Close all nodes
    node1.close();
    node2.close();
