    varB.value(true);
    varC.value(false);

    const bool updatedAnd = andReact.get();
    const bool updatedOr = orReact.get();

    return LogicalExpressionSnapshot{
        .initialAnd = initialAnd,
        .initialOr = initialOr,
        .updatedAnd = updatedAnd,
        .updatedOr = updatedOr,
    };
}

